	}
	success := 0
	fail := 0
	for _, tunnelID := range ids {
		if err := h.redeployTunnelAndForwards(tunnelID); err != nil {
			fail++
			continue
		}
		success++
	}
	response.WriteJSON(w, response.OK(map[string]interface{}{"successCount": success, "failCount": fail}))
}

