	for i, fp := range ports {
		entries[i] = struct {
			NodeID int64
			Port   int
			InIP   string
		}{NodeID: fp.NodeID, Port: fp.Port, InIP: fp.InIP}
	}
	return h.repo.ReplaceForwardPorts(forwardID, entries)
